 50‚Üí// ID-maps the given mountpoint, using the given userns ID mappings; both paths must be absolute.
 51‚Üífunc IDMapMount(usernsPath, mountPath string, unmountFirst bool) error {
 52‚Üí
 53‚Üí	// open the usernsPath
 54‚Üí	usernsFd, err := os.Open(usernsPath)
 55‚Üí	if err != nil {
 56‚Üí		return fmt.Errorf("Failed to open %s: %s", usernsPath, err)
 57‚Üí	}
 58‚Üí	defer usernsFd.Close()
 59‚Üí
 60‚Üí	// If mountPath is procfd based, read the magic link
 61‚Üí	if strings.HasPrefix(mountPath, "/proc/self/fd/") {
 62‚Üí		mountPath, err = os.Readlink(mountPath)
 63‚Üí		if err != nil {
 64‚Üí			return fmt.Errorf("Failed to read link %s: %s", mountPath, err)
 65‚Üí		}
 66‚Üí	} else {
 67‚Üí		mountPath, err = filepath.EvalSymlinks(mountPath)
 68‚Üí		if err != nil {
 69‚Üí			return fmt.Errorf("Failed to eval symlink on %s: %s", mountPath, err)
 70‚Üí		}
 71‚Üí	}
 72‚Üí
 73‚Üí	// clone the given mount
 74‚Üí	fdTree, err := unix.OpenTree(-1, mountPath, unix.OPEN_TREE_CLONE|unix.OPEN_TREE_CLOEXEC|unix.AT_EMPTY_PATH|unix.AT_RECURSIVE)
 75‚Üí	if err != nil {
 76‚Üí		return fmt.Errorf("Failed to open mount at %s: %s", mountPath, err)
 77‚Üí	}
 78‚Üí
 79‚Üí	// Set the ID-mapped mount attribute on the clone
 80‚Üí	// TODO: add propagation type? (use the original mountpoints propagation)?
 81‚Üí
 82‚Üí	mountAttr := &unix.MountAttr{
 83‚Üí		Attr_set:  unix.MOUNT_ATTR_IDMAP,
 84‚Üí		Userns_fd: uint64(usernsFd.Fd()),
 85‚Üí	}
 86‚Üí
 87‚Üí	err = unix.MountSetattr(int(fdTree), "", unix.AT_EMPTY_PATH|unix.AT_RECURSIVE, mountAttr)
 88‚Üí	if err != nil {
 89‚Üí		return fmt.Errorf("Failed to set mount attr: %s", err)
 90‚Üí	}
 91‚Üí
 92‚Üí	// Unmount the original mountPath mount to prevent redundant / stacked mounting
 93‚Üí	if unmountFirst {
 94‚Üí		err = unix.Unmount(mountPath, unix.MNT_DETACH)
 95‚Üí		if err != nil {
 96‚Üí			return fmt.Errorf("Failed to unmount %s: %s", mountPath, err)
 97‚Üí		}
 98‚Üí	}
 99‚Üí
100‚Üí	// Attach the clone to the to mount point
101‚Üí	err = unix.MoveMount(fdTree, "", -1, mountPath, unix.MOVE_MOUNT_F_EMPTY_PATH)
102‚Üí	if err != nil {
103‚Üí		return fmt.Errorf("Failed to move mount: %s", err)
104‚Üí	}
105‚Üí
106‚Üí	unix.Close(fdTree)
107‚Üí	return nil
108‚Üí}
