143‚Üí// runIDMapMountCheckOnHost runs a quick test on the host to check if ID-mapping is
144‚Üí// supported. dir is the path where the test will run. If checkOnOverlayfs
145‚Üí// is true, the test checks if overlayfs supports ID-mapped lower layers.
146‚Üífunc runIDMapMountCheckOnHost(dir string, checkOnOverlayfs bool) (bool, error) {
147‚Üí	var (
148‚Üí		lowerDir, upperDir, workDir, idMapDir string
149‚Üí	)
150‚Üí
151‚Üí	tmpDir, err := os.MkdirTemp(dir, "sysbox-ovfs-check")
152‚Üí	if err != nil {
153‚Üí		return false, err
154‚Üí	}
155‚Üí	defer func() {
156‚Üí		os.RemoveAll(tmpDir)
157‚Üí	}()
158‚Üí
159‚Üí	testDir := filepath.Join(tmpDir, "merged")
160‚Üí	if err := os.Mkdir(testDir, 0700); err != nil {
161‚Üí		return false, err
162‚Üí	}
163‚Üí
164‚Üí	if checkOnOverlayfs {
165‚Üí		lowerDir = filepath.Join(tmpDir, "lower")
166‚Üí		upperDir = filepath.Join(tmpDir, "upper")
167‚Üí		workDir = filepath.Join(tmpDir, "work")
168‚Üí
169‚Üí		dirs := []string{lowerDir, upperDir, workDir}
170‚Üí		for _, dir := range dirs {
171‚Üí			if err := os.Mkdir(dir, 0700); err != nil {
172‚Üí				return false, err
173‚Üí			}
174‚Üí		}
175‚Üí	}
176‚Üí
177‚Üí	// Create a userns process that simply pauses until killed
178‚Üí	execFunc := func() {
179‚Üí		for i := 0; i < 3600; i++ {
180‚Üí			time.Sleep(1 * time.Second)
181‚Üí		}
182‚Üí	}
183‚Üí
184‚Üí	idmap := &specs.LinuxIDMapping{
185‚Üí		ContainerID: 0,
186‚Üí		HostID:      0,
187‚Üí		Size:        1,
188‚Üí	}
189‚Üí
190‚Üí	pid, childKill, err := linuxUtils.CreateUsernsProcess(idmap, execFunc, testDir, false, false)
191‚Üí	if err != nil {
192‚Üí		return false, err
193‚Üí	}
194‚Üí
195‚Üí	defer func() {
196‚Üí		var wstatus syscall.WaitStatus
197‚Üí		var rusage syscall.Rusage
198‚Üí		childKill()
199‚Üí		syscall.Wait4(pid, &wstatus, 0, &rusage)
200‚Üí	}()
201‚Üí
202‚Üí	// Create the ID mapped mount associated with the child process user-ns
203‚Üí	usernsPath := fmt.Sprintf("/proc/%d/ns/user", pid)
204‚Üí
205‚Üí	if checkOnOverlayfs {
206‚Üí		idMapDir = lowerDir
207‚Üí	} else {
208‚Üí		idMapDir = testDir
209‚Üí	}
210‚Üí
211‚Üí	if err := IDMapMount(usernsPath, idMapDir, false); err != nil {
212‚Üí		return false, errors.Wrap(err, "create mapped mount")
213‚Üí	}
214‚Üí	defer unix.Unmount(idMapDir, unix.MNT_DETACH)
215‚Üí
216‚Üí	if checkOnOverlayfs {
217‚Üí		opts := fmt.Sprintf("lowerdir=%s,upperdir=%s,workdir=%s", lowerDir, upperDir, workDir)
218‚Üí		flags := uintptr(0)
219‚Üí		if err := unix.Mount("overlay", testDir, "overlay", flags, opts); err != nil {
220‚Üí			return false, err
221‚Üí		}
222‚Üí		unix.Unmount(testDir, unix.MNT_DETACH)
223‚Üí		return true, nil
224‚Üí	}
225‚Üí
226‚Üí	return true, nil
227‚Üí}
